sparql_query:
PREFIX goo:        <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:       <http://example.org/resource#>
PREFIX geosparql:  <http://www.opengis.net/ont/geosparql#>
PREFIX geof:       <http://www.opengis.net/def/function/geosparql/>
PREFIX xsd:        <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:        <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:       <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?state ?hurricaneLandfallCount ?averageCountySviOverallScore
WHERE {
  {
    SELECT ?state (COUNT(DISTINCT ?cyclone) AS ?hurricaneLandfallCount)
    WHERE {
      ?state a goo:State ;
             geosparql:hasGeometry ?stateGeom .
      ?stateGeom geosparql:asWKT ?stateWKT .
      ?cyclone a goo:HurricaneEventRecord ;
               goo:hasTrackRecord ?track .
      ?track a goo:HurricaneTrackRecord ;
             goo:status "HU"^^xsd:string ;
             goo:lat ?trackLat ;
             goo:lon ?trackLon .
      BIND(STRDT(CONCAT("POINT(", STR(?trackLon), " ", STR(?trackLat), ")"), geosparql:wktLiteral) AS ?trackPoint)
      FILTER (geof:sfWithin(?trackPoint, ?stateWKT))
    }
    GROUP BY ?state
  }
  OPTIONAL {
    SELECT ?state (AVG(?sviScore) AS ?averageCountySviOverallScore)
    WHERE {
      ?county a goo:County ;
              goo:locatedInState ?state .
      ?sviRecord a goo:SVIRecord ;
                 goo:representsCounty ?county ;
                 goo:sviOverallScore ?sviScore .
    }
    GROUP BY ?state
  }
}
ORDER BY DESC(?hurricaneLandfallCount) DESC(?averageCountySviOverallScore)
LIMIT 10
